const ProductCarousel = ({ images, currentIndex, onPrevious, onNext }) => {
  return (
    <div
      role="region"
      aria-label="Carrousel de produits"
      className="carousel"
    >
      <div
        role="group"
        aria-roledescription="diapositive"
        aria-label={`Image ${currentIndex + 1} sur ${images.length}`}
        className="carousel-slide"
      >
        <img src={images[currentIndex]} alt={`Produit vue ${currentIndex + 1}`} />
      </div>

      <button
        onClick={onPrevious}
        aria-label="Image précédente"
        disabled={currentIndex === 0}
      >
        ◀
      </button>

      <button
        onClick={onNext}
        aria-label="Image suivante"
        disabled={currentIndex === images.length - 1}
      >
        ▶
      </button>

      <div aria-live="polite" className="sr-only">
        {`Affichage de l'image ${currentIndex + 1} sur ${images.length}`}
      </div>
    </div>
  );
};
